const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const corrections = require('./corrections.json');

// ===== 천간/지지 상수 =====
const STEMS = ['甲','乙','丙','丁','戊','己','庚','辛','壬','癸'];
const STEMS_KR = ['갑','을','병','정','무','기','경','신','임','계'];
const BRANCHES = ['子','丑','寅','卯','辰','巳','午','未','申','酉','戌','亥'];
const BRANCHES_KR = ['자','축','인','묘','진','사','오','미','신','유','술','해'];
const STEM_ELEMENT = { '甲':'목','乙':'목','丙':'화','丁':'화','戊':'토','己':'토','庚':'금','辛':'금','壬':'수','癸':'수' };

function pillar(stemIdx, branchIdx) {
  const s = STEMS[stemIdx % 10];
  const b = BRANCHES[branchIdx % 12];
  return { stem: s, branch: b, stemKr: STEMS_KR[stemIdx % 10], branchKr: BRANCHES_KR[branchIdx % 12] };
}

function generateSaju(birthYear, birthMonth, birthDay, hourIdx) {
  // Simplified four pillars based on birth data
  const yearStemIdx = (birthYear - 4) % 10;
  const yearBranchIdx = (birthYear - 4) % 12;
  const monthStemIdx = (yearStemIdx * 2 + birthMonth) % 10;
  const monthBranchIdx = (birthMonth + 1) % 12;
  const dayStemIdx = (birthYear * 5 + Math.floor(birthYear / 4) + birthDay + birthMonth * 3) % 10;
  const dayBranchIdx = (dayStemIdx + birthDay) % 12;
  const hourStemIdx = (dayStemIdx * 2 + hourIdx) % 10;
  const hourBranchIdx = hourIdx % 12;

  const pillars = {
    year: pillar(yearStemIdx, yearBranchIdx),
    month: pillar(monthStemIdx, monthBranchIdx),
    day: pillar(dayStemIdx, dayBranchIdx),
    hour: pillar(hourStemIdx, hourBranchIdx),
  };

  const dayMaster = pillars.day.stem;
  const dmElement = STEM_ELEMENT[dayMaster];

  // Calculate five elements distribution
  const allStems = [pillars.year.stem, pillars.month.stem, pillars.day.stem, pillars.hour.stem];
  const elCounts = { '목': 0, '화': 0, '토': 0, '금': 0, '수': 0 };
  allStems.forEach(s => { elCounts[STEM_ELEMENT[s]] += 12.5; });
  const BRANCH_EL = { '寅':'목','卯':'목','巳':'화','午':'화','辰':'토','未':'토','丑':'토','戌':'토','申':'금','酉':'금','子':'수','亥':'수' };
  [pillars.year.branch, pillars.month.branch, pillars.day.branch, pillars.hour.branch].forEach(b => {
    if (BRANCH_EL[b]) elCounts[BRANCH_EL[b]] += 12.5;
  });

  // Normalize to 100
  const total = Object.values(elCounts).reduce((a, b) => a + b, 0);
  const elements = {};
  Object.keys(elCounts).forEach(k => { elements[k] = Math.round(elCounts[k] / total * 100 * 10) / 10; });

  // Strength
  const dmCount = elements[dmElement] || 0;
  const strength = dmCount >= 30 ? '신강' : dmCount >= 20 ? '중화신강' : dmCount >= 15 ? '중화신약' : '신약';
  const strengthLabel = dmCount >= 30 ? '身強' : dmCount >= 20 ? '中和身強' : dmCount >= 15 ? '中和身弱' : '身弱';

  // Structure
  const structures = ['편재격', '정재격', '식신격', '상관격', '편관격', '정관격', '편인격', '정인격', '건록격'];
  const structure = structures[(dayStemIdx + monthBranchIdx) % structures.length];

  // Yongshin (needed elements)
  const weak = Object.entries(elements).filter(([, v]) => v < 15).map(([k]) => k);
  const yongshin = weak.length > 0 ? weak.slice(0, 2) : [dmElement];
  const heesin = [yongshin[0] || dmElement];
  const strong = Object.entries(elements).filter(([, v]) => v > 25).map(([k]) => k);
  const gisin = strong.length > 0 ? strong.slice(0, 2) : [];

  return { dayMaster, elements, strength, strengthLabel, structure, yongshin, heesin, gisin, pillars };
}

