// ===== Build members with saju data and corrections =====
function buildMember(raw) {
  const [bYear, bMonth, bDay, bHour] = raw.birth || [1992, 1, 1, 8];
  const saju = generateSaju(bYear, bMonth, bDay, bHour);
  saju.profile = raw.sajuProfile;
  saju.birthDate = `${bYear}-${String(bMonth).padStart(2,'0')}-${String(bDay).padStart(2,'0')}`;
  saju.birthTime = `${String(bHour).padStart(2,'0')}:${String(Math.floor(bHour * 7) % 60).padStart(2,'0')}`;
  saju.birthTimeUnknown = false;

  const member = {
    id: raw.id, name: raw.name, age: raw.age, gender: raw.gender,
    job: raw.job, income: raw.income, edu: raw.edu,
    height: raw.height, weight: raw.weight, bodyType: raw.bodyType,
    assets: raw.assets, family: raw.family, appearanceNote: raw.appearanceNote,
    location: raw.location, verifyLevel: raw.verifyLevel, verifyItems: raw.verifyItems,
    saju,
    grade: null, // will be overwritten by corrections
    values: raw.values, status: raw.status, manager: raw.manager,
    lastContact: getLastContactLabel(raw.lastContactDate),
    nextAction: getNextAction(raw),
    profileCompletion: raw.profileCompletion, outboundProposals: raw.outboundProposals,
    reminderCycle: raw.reminderCycle, lastContactDate: raw.lastContactDate,
    meetings: raw.meetings || [], notes: raw.notes || '', photos: [],
  };

  // Apply corrections
  if (corrections[raw.id]) {
    member.family = corrections[raw.id].family;
    member.grade = corrections[raw.id].grade;
  }

  return member;
}

function getLastContactLabel(dateStr) {
  if (!dateStr) return '미정';
  const d = new Date(dateStr);
  const today = new Date('2026-03-14');
  const diff = Math.floor((today - d) / (86400000));
  if (diff === 0) return '오늘';
  if (diff === 1) return '어제';
  return `${diff}일 전`;
}

function getNextAction(raw) {
  const meetings = raw.meetings || [];
  if (meetings.length === 0) return '재컨택 필요';
  const future = meetings.filter(m => m.date >= '2026-03-14').sort((a,b) => a.date.localeCompare(b.date));
  if (future.length === 0) return '재컨택 필요';
  const next = future[0];
  const d = new Date(next.date);
  const today = new Date('2026-03-14');
  const diff = Math.floor((d - today) / 86400000);
  if (diff === 0) return `오늘 ${next.time || ''}`.trim();
  if (diff === 1) return `내일 ${next.time || ''}`.trim();
  return `${next.date.slice(5)} ${next.time || ''}`.trim();
}

// ===== Generate output =====
const allMembers = MEMBERS_RAW.map(buildMember);

// Get non-member exports from HEAD
const headContent = execSync('git show HEAD:src/lib/seedData.js', { encoding: 'utf8', cwd: path.join(__dirname, '..') });

// Find where networkMembers ends in HEAD
const nmEndMarker = '];\n\nexport const inboxItems';
const splitIdx = headContent.indexOf(nmEndMarker);
const otherExports = splitIdx >= 0 ? headContent.substring(splitIdx + 3) : ''; // skip "];\n\n"

// Build final file
let output = 'export const initialMembers = [\n';
allMembers.forEach((m, i) => {
  output += `  ${JSON.stringify(m)}${i < allMembers.length - 1 ? ',' : ''}\n`;
});
output += '];\n\nexport const networkMembers = [\n';
NETWORK_RAW.forEach((m, i) => {
  output += `  ${JSON.stringify(m)}${i < NETWORK_RAW.length - 1 ? ',' : ''}\n`;
});
output += '];\n\n';
output += otherExports;

const outPath = path.join(__dirname, '..', 'src', 'lib', 'seedData.js');
fs.writeFileSync(outPath, output, 'utf8');

console.log(`✅ seedData.js 재생성 완료`);
console.log(`   initialMembers: ${allMembers.length}명`);
console.log(`   networkMembers: ${NETWORK_RAW.length}명`);
console.log(`   기타 exports: ${otherExports.split('export const').length - 1}개`);
